JobRandomPool = class()

function JobRandomPool:ctor(poolId)
    self.poolId = poolId
    self.weightSum = 0
    self.items = {}
end

--添加职业到池子里
function JobRandomPool:addJobToPool(itemConfig)
    local item = {
        weight = itemConfig.weight,
        id =itemConfig.id
    }
    self.weightSum = self.weightSum + item.weight
    table.insert(self.items, item)
end

--从相同品质池子里随机取职业
function JobRandomPool:randomJob(num)
    local maxWeight = self.weightSum
    local jobsList = {}
    local tab = TableUtil.copyTable(self.items)
    local count = math.min(num, #self.items)
    while count > 0 do
        local random = math.random(1, maxWeight)
        local weight = 0
        for pos, item in pairs(tab) do
            weight = weight + item.weight
            if weight >= random then
                table.insert(jobsList, item)
                maxWeight = maxWeight - item.weight
                table.remove(tab, pos)
                break
            end
        end
        count = count - 1
    end
    return jobsList
end